"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeApprovePayment — verdict surface for signing off a large outflow.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Finance/
   magellan-finance-approve-payment.html

   "Reorder inverted, money out" — same verdict-surface shape as BridgeReorder.
   Pattern:
   - Payment summary (context bar: amount / due / cash now)
   - Duplicate-payment safety banner (clear → amber warn when ref collides)
   - "When to pay" form: timing segment (Pay now / on due / Hold) → pay date,
     method, reference, attachment chips, the outflow breakdown
   - Verdict (APPROVE / REVIEW / HOLD) with 4 factor dots
   - "What this does to your cash" — 2 tiers (This payment + Same window)

   Timing recomputes the cash read + verdict on change. A reference matching a
   seeded recent payment trips the amber duplicate warning and flips the
   verdict to REVIEW — the headline safety feature (model spec §8.2).
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import { APPROVE_PAYMENT_DATA } from "@/features/finance/api/finance-approve-payment-data";
import "./BridgeApprovePayment.css";

type Timing = "now" | "due" | "hold";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const fmtUSDK = (v: number) => {
  const abs = Math.abs(v);
  const sign = v < 0 ? "-" : "";
  if (abs >= 1000) return `${sign}$${(abs / 1000).toFixed(1).replace(/\.0$/, "")}K`;
  return `${sign}$${Math.round(abs)}`;
};

export function BridgeApprovePayment() {
  const { setPage } = useBridge();
  const { payment, cash, duplicateRefs, recentPayments } = APPROVE_PAYMENT_DATA;

  const [timing, setTiming] = useState<Timing>("due");
  const [reference, setReference] = useState(payment.reference);
  const [approved, setApproved] = useState(false);

  // Duplicate check — the reference colliding with a recent payment trips it.
  const duplicate = useMemo(() => {
    const ref = reference.trim();
    if (!ref) return null;
    if (!duplicateRefs.includes(ref)) return null;
    // pull the matching recent payment for the warning copy
    return recentPayments.find((p) => p.ref === ref) ?? recentPayments[0] ?? null;
  }, [reference, duplicateRefs, recentPayments]);

  const calc = useMemo(() => {
    const payNow = timing === "now";
    const hold = timing === "hold";

    const discount = payNow ? Math.round(payment.amount * payment.earlyPayDiscount) : 0;
    const out = payment.amount - discount;
    const cashAfter = hold ? cash.cashNow : cash.cashNow - out;

    const runwayNow = cash.runwayMonths;
    const runwayAfter = hold
      ? runwayNow
      : Math.round((cashAfter / cash.monthlyBurn) * 10) / 10;

    const pctCash = out / cash.cashNow;
    const floatKept = payNow ? 0 : payment.netDays - payment.dueInDays; // 26 days

    // Net cash for the week: inflows in − (this payment + other due)
    const weekOut = (hold ? 0 : out) + cash.otherDue;
    const netWeek = cash.inflows - weekOut;
    const floorHeld = runwayAfter >= cash.runwayFloorMonths;

    return {
      payNow,
      hold,
      discount,
      out,
      cashAfter,
      runwayNow,
      runwayAfter,
      pctCash,
      floatKept,
      netWeek,
      floorHeld,
    };
  }, [timing, payment, cash]);

  // Verdict — duplicate overrides everything, else timing + cash share.
  const verdict = useMemo(() => {
    if (duplicate) {
      return {
        cls: "hold" as const,
        mark: "REVIEW",
        line: `Hold up — this looks like a payment you already made ${duplicate.daysAgo} days ago. Clear the duplicate flag before approving, or you risk paying ${payment.payee} twice.`,
      };
    }
    if (calc.hold) {
      return {
        cls: "hold" as const,
        mark: "HOLD",
        line: `Holding is fine if cash is tight or you're disputing the invoice — but it's a matched COGS bill due in ${payment.dueInDays} days. Don't let it slip past terms or you risk the supplier relationship.`,
      };
    }
    if (calc.pctCash > 0.4) {
      return {
        cls: "hold" as const,
        mark: "REVIEW",
        line: "This is a large share of your cash. It clears, but check nothing else big is due in the same window before approving.",
      };
    }
    if (calc.payNow) {
      return {
        cls: "" as const,
        mark: "APPROVE",
        line: `Safe to pay, and the 2% early-pay discount (${fmtUSD(calc.discount)}) beats holding the cash ${payment.netDays - payment.dueInDays} days at your scale. Paying now is the better move here.`,
      };
    }
    return {
      cls: "" as const,
      mark: "APPROVE",
      line: "Safe to pay — matched COGS invoice, cash covers it comfortably, and paying on the due date keeps your float.",
    };
  }, [duplicate, calc, payment]);

  // Factor dots
  const matchDot = duplicate ? "bad" : "ok";
  const matchText = duplicate
    ? `Matches a payment from ${duplicate.daysAgo} days ago — possible double-pay`
    : `Tied to ${payment.attachments.filter((a) => a.have).map((a) => a.label).join(" & ")} — not a duplicate`;
  const cashDot = calc.pctCash > 0.4 ? "warn" : "ok";
  const timingDot = calc.hold ? "warn" : calc.payNow ? "ok" : "warn";
  const timingText = calc.payNow
    ? `Early-pay discount ${fmtUSD(calc.discount)} — worth taking`
    : calc.hold
      ? "Held — watch the due date"
      : `Paying on terms beats early — keep the cash ${payment.netDays - payment.dueInDays} more days`;

  // Read-outs
  const payDate = calc.payNow
    ? "today · early"
    : calc.hold
      ? "not scheduled"
      : `${payment.dueDateLabel} · on terms`;

  const approve = () => {
    setApproved(true);
    setTimeout(() => {
      setApproved(false);
      setPage("home");
    }, 1800);
  };

  const commitLabel = calc.hold
    ? "Hold payment — revisit later →"
    : calc.payNow
      ? `Approve — pay ${fmtUSD(calc.out)} today →`
      : `Approve — pay ${fmtUSD(payment.amount)} on ${payment.dueDateLabel} →`;

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="9" />
            <path d="M8 12 l2.5 2.5 L16 9" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Approve Payment</div>
          <div className="bridge-page-head-sub">
            A large outflow needs sign-off. Magellan checks it against your cash and runway, then you approve, schedule, or hold.
          </div>
        </div>
      </div>

      {/* The payment */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">
            {payment.payee} &mdash; invoice {payment.invoice}
          </div>
          <div className="bridge-rb-sku-meta">{payment.meta}</div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(payment.amount)}</span>
            <span className="bridge-rb-stat-k">amount</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v alert">in {payment.dueInDays} days</span>
            <span className="bridge-rb-stat-k">due</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSDK(cash.cashNow)}</span>
            <span className="bridge-rb-stat-k">cash now</span>
          </div>
        </div>
      </div>

      {/* Duplicate-payment safety check */}
      <div className={`bridge-ap-dupcheck ${duplicate ? "warn" : "clear"}`}>
        <div className="bridge-ap-dupcheck-ic">
          {duplicate ? (
            <svg viewBox="0 0 24 24">
              <path d="M12 9 v4 M12 17 h.01" />
              <path d="M10.3 3.9 L1.8 18 a2 2 0 0 0 1.7 3 h17 a2 2 0 0 0 1.7 -3 L13.7 3.9 a2 2 0 0 0 -3.4 0 z" />
            </svg>
          ) : (
            <svg viewBox="0 0 24 24">
              <path d="M20 6 L9 17 l-5 -5" />
            </svg>
          )}
        </div>
        <div>
          {duplicate ? (
            <>
              <b>Possible duplicate.</b> A payment to {duplicate.payee} for {fmtUSD(duplicate.amount)} (ref {reference.trim()}) was recorded {duplicate.daysAgo} days ago. Paying again may double-pay this invoice &mdash; confirm before approving.
            </>
          ) : (
            <>
              <b>No duplicate found.</b> Magellan checked the last 90 days &mdash; no payment to {payment.payee} for {fmtUSD(payment.amount)} or invoice {payment.invoice}. Safe to proceed.
            </>
          )}
        </div>
        {duplicate && (
          <button type="button" className="bridge-ap-dupcheck-act">
            Show the match
          </button>
        )}
      </div>

      {/* The payment decision */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">When to pay</span>
          <span className="bridge-ni-source manual">&#9998; Magellan suggests by terms &amp; cash — adjust freely</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">Timing</span>
            <div className="bridge-ni-seg">
              <button type="button" className={timing === "now" ? "on" : ""} onClick={() => setTiming("now")}>
                Pay now
              </button>
              <button type="button" className={timing === "due" ? "on" : ""} onClick={() => setTiming("due")}>
                Pay on due date
              </button>
              <button type="button" className={timing === "hold" ? "on" : ""} onClick={() => setTiming("hold")}>
                Hold
              </button>
            </div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Pay date</span>
            <div className="bridge-ni-readout">{payDate}</div>
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Method</span>
            <div className="bridge-ni-readout">{payment.method}</div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">
              Payment reference
              <span className="bridge-ap-hint">for reconciliation</span>
            </span>
            <input
              className="bridge-ni-input"
              type="text"
              value={reference}
              onChange={(e) => setReference(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Documents on file</span>
            <div className="bridge-ap-atch-row">
              {payment.attachments.map((a) => (
                <span key={a.label} className={`bridge-ap-atch ${a.have ? "have" : "miss"}`}>
                  {a.have ? "✓ " : ""}
                  {a.label}
                </span>
              ))}
            </div>
          </div>

          <div className="bridge-ni-cost bridge-ni-span">
            <div className="bridge-ni-cost-head">
              <span className="bridge-ni-label">The outflow</span>
              <span className="bridge-ni-cost-note">what leaves and when</span>
            </div>
            <div className="bridge-ni-cost-row">
              <span>Invoice amount</span>
              <span className="bridge-rb-num">{fmtUSD(payment.amount)}</span>
            </div>
            <div className="bridge-ni-cost-row add">
              <span>
                Early-pay discount ({Math.round(payment.earlyPayDiscount * 100)}% if now)
              </span>
              <span className={`bridge-rb-num${calc.payNow ? " good" : ""}`}>
                {calc.payNow ? `−${fmtUSD(calc.discount)}` : "—"}
              </span>
            </div>
            <div className="bridge-ni-cost-total">
              <span className="lbl">Cash out</span>
              <span className="bridge-ni-landed">{calc.hold ? "—" : fmtUSD(calc.out)}</span>
            </div>
          </div>
        </div>
      </div>

      {/* The verdict */}
      <div className={`bridge-rb-verdict ${verdict.cls}`}>
        <div
          className="bridge-rb-verdict-mark"
          style={
            verdict.mark === "APPROVE"
              ? { color: "var(--d-finance)", width: 112 }
              : { width: 112 }
          }
        >
          {verdict.mark}
        </div>
        <div className="bridge-rb-verdict-body">
          <div className="bridge-rb-verdict-line">{verdict.line}</div>
          <div className="bridge-rb-verdict-factors">
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${matchDot}`} />
              <span className="bridge-rb-factor-k">Matched</span>
              <span className="bridge-rb-factor-v">{matchText}</span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${cashDot}`} />
              <span className="bridge-rb-factor-k">Cash covers it</span>
              <span className="bridge-rb-factor-v">
                {fmtUSD(calc.out)} of {fmtUSDK(cash.cashNow)} &mdash; {(calc.pctCash * 100).toFixed(1)}% of cash
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot ok" />
              <span className="bridge-rb-factor-k">Runway holds</span>
              <span className="bridge-rb-factor-v">
                {calc.runwayNow.toFixed(1)} &rarr; {calc.runwayAfter.toFixed(1)} months after
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${timingDot}`} />
              <span className="bridge-rb-factor-k">Timing</span>
              <span className="bridge-rb-factor-v">{timingText}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Cash-impact read */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this does to your cash
          <span className="bridge-ni-outcome-prov firm">Computed from your ledger</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This payment</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Cash out</span>
              <span className="v">{calc.hold ? "—" : fmtUSDK(calc.out)}</span>
              <span className="kk">{calc.hold ? "not scheduled" : `on ${calc.payNow ? "today" : payment.dueDateLabel}`}</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Cash now</span>
              <span className="v">{fmtUSDK(cash.cashNow)}</span>
              <span className="kk">spendable</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">After it clears</span>
              <span className="v">{fmtUSDK(calc.cashAfter)}</span>
              <span className="kk">still above floor</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Float kept</span>
              <span className={`v${!calc.payNow && !calc.hold ? " good" : ""}`}>
                {calc.payNow ? "0 days" : calc.hold ? "—" : `${calc.floatKept} days`}
              </span>
              <span className="kk">vs paying now</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Same window</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Other payments due</span>
              <span className="v">{fmtUSDK(cash.otherDue)}</span>
              <span className="kk">{cash.otherDueCount} in next {cash.windowDays} days</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Inflows expected</span>
              <span className="v good">+{fmtUSDK(cash.inflows)}</span>
              <span className="kk">{cash.inflowsSource}</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Net cash this week</span>
              <span className={`v${calc.netWeek >= 0 ? " good" : " alert"}`}>
                {calc.netWeek >= 0 ? "+" : ""}
                {fmtUSDK(calc.netWeek)}
              </span>
              <span className="kk">after all clears</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Runway floor held?</span>
              <span className={`v${calc.floorHeld ? " good" : " alert"}`}>
                {calc.floorHeld ? "Yes" : "No"}
              </span>
              <span className="kk">stays above {cash.runwayFloorMonths} months</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Approving doesn&rsquo;t pay immediately &mdash; it commits the outflow on the chosen date and the ledger reflects it then. Magellan checks the payment is <b>matched</b> (not a duplicate or unbacked charge), that <b>cash and runway hold</b> after it and the other payments in the window clear, and whether paying on terms vs. early is the better cash move.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the approval &mdash; the payment <b>isn&rsquo;t sent</b> until the pay date, and you can reverse before then.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Hold
          </button>
          <button
            className={`bridge-ni-create${approved ? " done" : ""}`}
            type="button"
            onClick={approve}
            disabled={approved}
          >
            {approved ? "✓ Payment approved" : commitLabel}
          </button>
        </div>
      </div>
    </div>
  );
}
