/** A single attachment chip in the "Documents on file" row. */
export interface ApAttachment {
  /** Mono-caps label shown on the chip (e.g. "Invoice", "PO #4137"). */
  label: string;
  /** True = on file (finance-green ✓ chip); false = missing (muted chip). */
  have: boolean;
}

/** A recent payment the duplicate-check scans against. */
export interface ApRecentPayment {
  /** Payment reference recorded on the ledger. */
  ref: string;
  /** Payee. */
  payee: string;
  /** Amount, USD. */
  amount: number;
  /** How many days ago it was recorded. */
  daysAgo: number;
}

/** The payment being approved. */
export interface ApPayment {
  /** Payee + invoice headline. */
  payee: string;
  invoice: string;
  /** Context-bar sub-line (classification · terms · provenance · match). */
  meta: string;
  /** Invoice amount, USD. */
  amount: number;
  /** Days until the invoice is due. */
  dueInDays: number;
  /** Human pay date on terms (e.g. "Jun 22"). */
  dueDateLabel: string;
  /** Payment terms net days (Net 30 → 30). */
  netDays: number;
  /** Early-pay discount as a fraction of the amount if paid now (0.02 = 2%). */
  earlyPayDiscount: number;
  /** Default payment reference, pre-filled for reconciliation. */
  reference: string;
  /** Payment method read-out. */
  method: string;
  /** Documents on file. */
  attachments: ApAttachment[];
}

/** Cash context the verdict + read are computed against. */
export interface ApCashContext {
  /** Spendable cash now, USD. */
  cashNow: number;
  /** Other payments due in the same 7-day window, USD. */
  otherDue: number;
  /** Count of those other payments. */
  otherDueCount: number;
  /** Window length, days. */
  windowDays: number;
  /** Inflows expected in the window, USD. */
  inflows: number;
  /** Inflows source caption. */
  inflowsSource: string;
  /** Current runway, months. */
  runwayMonths: number;
  /** Monthly burn, USD — used to project runway after the outflow. */
  monthlyBurn: number;
  /** Runway floor the business must stay above, months. */
  runwayFloorMonths: number;
}

/** Full surface payload. */
export interface ApData {
  payment: ApPayment;
  cash: ApCashContext;
  /** Recent payments scanned by the duplicate check (last 90 days). */
  recentPayments: ApRecentPayment[];
  /** References that, when typed into the reference field, trip the
      duplicate warning in the demo (collide with a payment 11 days ago). */
  duplicateRefs: string[];
}

